DROP TABLE IF EXISTS `stocks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `stocks` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `symbol` varchar(20) NOT NULL COMMENT 'Stock symbol',
  `name` varchar(100) NOT NULL COMMENT 'Stock name',
  `exchange` varchar(20) DEFAULT NULL COMMENT 'Exchange',
  `industry` varchar(50) DEFAULT NULL COMMENT 'Industry',
  `market_cap` decimal(20,2) DEFAULT NULL COMMENT 'Market cap',
  `status` int NOT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `float_shares` bigint DEFAULT NULL,
  `total_shares` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `symbol` (`symbol`),
  KEY `idx_symbol` (`symbol`),
  KEY `idx_name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=5725 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='Stocks table';
